// 获取输入数据
const data = $input.all().map(item => item.json);

// 分页参数
const page = 1; // 注意：根据你的需求修改页码
const size = 10; // 注意：根据你的需求修改每页显示的条数

// 分页函数
function paginate(data, page, size) {
  const start = (page - 1) * size;
  return data.slice(start, start + size);
}

// 获取分页后的数据
const paginatedData = paginate(data, page, size);

// 返回分页后的数据
return paginatedData.map(d => ({ json: d }));
